// AppTransitionController.java:169  master 实测
void handleAppTransitionReady() {
    mTempTransitionReasons.clear();
    if (!transitionGoodToGo(mDisplayContent.mOpeningApps, mTempTransitionReasons)
            || !transitionGoodToGo(mDisplayContent.mChangingContainers, mTempTransitionReasons)
            || !transitionGoodToGoForTaskFragments()) {
        return;        // ★ 窗口还没就绪就不走
    }
    Trace.traceBegin(Trace.TRACE_TAG_WINDOW_MANAGER, "AppTransitionReady");
    ProtoLog.v(WM_DEBUG_APP_TRANSITIONS, "**** GOOD TO GO");

    mDisplayContent.forAllWindows(WindowState::cleanupAnimatingExitWindow, true);
    final AppTransition appTransition = mDisplayContent.mAppTransition;

    // 1) 清理 mAnimatingExit / 调整壁纸
    for (int i = 0; i < mDisplayContent.mOpeningApps.size(); ++i)
        mDisplayContent.mOpeningApps.valueAtUnchecked(i).clearAnimatingFlags();
    ...
    mWallpaperControllerLocked.adjustWallpaperWindowsForAppTransitionIfNeeded(...);

    // 2) 收集 opening/closing 集合
    ArraySet<ActivityRecord> tmpOpenApps = mDisplayContent.mOpeningApps;
    ArraySet<tmpCloseApps = mDisplayContent.mClosingApps;
    if (mAtmService.mBackNavigationController.isMonitoringFinishTransition()) {
        // 预测式返回动画过滤
        if (mAtmService.mBackNavigationController.removeIfContainsBackAnimationTargets(
                tmpOpenApps, tmpCloseApps)) {
            mAtmService.mBackNavigationController.clearBackAnimations(false);
        }
    }

    // 3) 决定 transit 类型
    @TransitionOldType final int transit = getTransitCompatType(
            mDisplayContent.mAppTransition, tmpOpenApps, tmpCloseApps,
            mDisplayContent.mChangingContainers,
            mWallpaperControllerLocked.getWallpaperTarget(), getOldWallpaper(),
            mDisplayContent.mSkipAppTransitionAnimation);

    // 4) 检查 RemoteAnimation / TaskFragment RemoteAnimation 覆盖
    if (!overrideWithTaskFragmentRemoteAnimation(transit, activityTypes)) {
        unfreezeEmbeddedChangingWindows();
        overrideWithRemoteAnimationIfSet(animLpActivity, transit, activityTypes);
    }

    // 5) 真正下发动画
    mService.mSurfaceAnimationRunner.deferStartingAnimations();
    try {
        applyAnimations(tmpOpenApps, tmpCloseApps, transit, animLp, voiceInteraction);
        handleClosingApps();
        handleOpeningApps();
        handleChangingApps(transit);
        handleClosingChangingContainers();
        appTransition.setLastAppTransition(transit, topOpeningApp, topClosingApp, topChangingApp);
        layoutRedo = appTransition.goodToGo(transit, topOpeningApp);   // ★ APP_STATE_IDLE→RUNNING
        appTransition.postAnimationCallback();
    } finally {
        appTransition.clear();
        mService.mSurfaceAnimationRunner.continueStartingAnimations();
    }

    mService.mSnapshotController.onTransitionStarting(mDisplayContent);
}
```

