    }
    // 2) 拆出 opening / closing WindowContainer 集合
    final ArraySet<WindowContainer> openingWcs = getAnimationTargets(openingApps, closingApps, true);
    final ArraySet<WindowContainer> closingWcs = getAnimationTargets(openingApps, closingApps, false);
    // 3) 递归下发
    applyAnimations(openingWcs, openingApps, transit, true /* visible */, animLp, voiceInteraction);
    applyAnimations(closingWcs, closingApps, transit, false /* visible */, animLp, voiceInteraction);
