// TransitionController.java:296
Transition createTransition(@WindowManager.TransitionType int type, int flags) {
    if (mTransitionPlayers.isEmpty()) {
        throw new IllegalStateException("Shell Transitions not enabled");
    }
    if (mCollectingTransition != null) {
        throw new IllegalStateException("Trying to directly start transition collection while"
                + " collection is already ongoing. Use startCollectOrQueue if possible.");
    }
    Transition transit = new Transition(type, flags, this, mSyncEngine);
    ProtoLog.v(WM_DEBUG_WINDOW_TRANSITIONS, "Creating Transition: %s", transit);
    moveToCollecting(transit);   // ★ mCollectingTransition = transit; transit.startCollecting(timeoutMs)
    return transit;
}
```

